def _mkt_customer_smooth_v142_after_request(response):
    try:
        if request.path.startswith('/admin') or request.path.startswith('/api') or request.path.startswith('/healthz'):
            return response
        ctype = response.headers.get('Content-Type','')
        if 'text/html' not in ctype.lower():
            return response
        data = response.get_data(as_text=True)
        if 'mkt-customer-smooth-v142-js' in data:
            return response
        if '</body>' in data:
            data = data.replace('</body>', _MKT_CUSTOMER_SMOOTH_V142_ADDON + '</body>', 1)
        else:
            data += _MKT_CUSTOMER_SMOOTH_V142_ADDON
        response.set_data(data)
        response.headers['Content-Length'] = str(len(response.get_data()))
    except Exception as e:
        print('Customer Smooth V142 inject skipped:', e)
    return response

try:
    if not getattr(app, '_mkt_customer_smooth_v142_installed', False):
        app.after_request(_mkt_customer_smooth_v142_after_request)
        app._mkt_customer_smooth_v142_installed = True
except Exception as _mkt_customer_smooth_v142_error:
    print('Customer Smooth V142 install skipped:', _mkt_customer_smooth_v142_error)
