  #mktSmoothCtvBtn,#mktMobileCtvLiveBtn,#mktMobileCtvQuick,#mktMobileCtvQuickRestore,#mobileCtvQuickBtn,#mktPhoneCtvDockFinal,#mktMobileActionDock .mkt-dock-ctv,.mkt-phone-ctv,button[aria-label="CTV"]{
