@app.route('/telegram/webhook', methods=['POST'])
def telegram_webhook_route():
    data = request.get_json(silent=True) or {}
    try:
        # Callback nút bấm inline
        cb = data.get('callback_query') or {}
        if cb:
            cb_id = cb.get('id')
            action = cb.get('data') or ''
            msg = cb.get('message') or {}
            chat_id = ((msg.get('chat') or {}).get('id')) or os.getenv('TELEGRAM_CHAT_ID','').strip()
            parts = action.split(':', 1)
            cmd = parts[0]
            arg = parts[1] if len(parts) > 1 else ''
            if cmd == 'approve':
                req_id = int(arg or 0)
                _device_for_reply = ''
                try:
                    _conn = db(); _c = _conn.cursor()
                    _c.execute('SELECT device_id FROM premium_upgrade_requests WHERE id=?', (req_id,))
                    _r = _c.fetchone(); _conn.close()
                    _device_for_reply = (_r[0] if _r else '') or ''
                except Exception:
                    _device_for_reply = ''
                ok = approve_premium_request(req_id, status='Đã duyệt', admin_note='Duyệt từ Telegram')
                _mkt_v160_tg_answer_callback(cb_id, 'Đã duyệt Premium' if ok else 'Không duyệt được')
                if ok and _device_for_reply:
                    try:
                        save_support_message(_device_for_reply, 'admin', 'Gói Premium của anh/chị đã được kích hoạt thành công. Anh/chị tải lại trang hoặc chờ vài giây để hệ thống tự mở khóa nhé.')
                    except Exception as _e:
                        print('Telegram approve customer notify skipped:', _e)
                _mkt_v160_tg_send(chat_id, '✅ Đã duyệt Premium yêu cầu #' + tg_safe(arg) if ok else '❌ Không tìm thấy yêu cầu #' + tg_safe(arg))
            elif cmd == 'reject':
                req_id = int(arg or 0)
                ok = approve_premium_request(req_id, status='Từ chối', admin_note='Từ chối từ Telegram')
                _mkt_v160_tg_answer_callback(cb_id, 'Đã từ chối' if ok else 'Không xử lý được')
                _mkt_v160_tg_send(chat_id, '⚠️ Đã từ chối yêu cầu #' + tg_safe(arg) if ok else '❌ Không tìm thấy yêu cầu #' + tg_safe(arg))
            elif cmd == 'days':
                _mkt_v160_tg_answer_callback(cb_id, 'Đang lấy ngày còn hạn')
                _mkt_v160_tg_send(chat_id, _mkt_v160_subscription_summary(arg))
            elif cmd == 'ctv':
                _mkt_v160_tg_answer_callback(cb_id, 'Đang lấy CTV')
                _mkt_v160_tg_send(chat_id, _mkt_v160_ctv_summary(arg))
            elif cmd == 'replyhint':
                _mkt_v160_tg_answer_callback(cb_id, 'Hướng dẫn trả lời')
                _mkt_v160_tg_send(chat_id, f"💬 Trả lời khách bằng lệnh:\n<code>/reply {tg_safe(arg)} nội dung cần gửi cho khách</code>")
            return jsonify({'ok': True})

        message = data.get('message') or data.get('edited_message') or {}
        chat_id = ((message.get('chat') or {}).get('id')) or os.getenv('TELEGRAM_CHAT_ID','').strip()
        text = (message.get('text') or '').strip()
        reply_text = ((message.get('reply_to_message') or {}).get('text') or '')
        if not text:
            return jsonify({'ok': True})

        low = text.lower()
        if low in ['/start', '/help', 'start', 'help']:
            _mkt_v160_tg_send(chat_id,
                "🤖 <b>GPTMini Telegram Admin</b>\n\n"
                "Lệnh nhanh:\n"
                "• /cho - xem Premium chờ duyệt\n"
                "• /duyet 123 - duyệt gói\n"
                "• /tuchoi 123 - từ chối\n"
                "• /reply MKT-ABC nội dung - trả lời khách\n"
                "• /ngay MKT-ABC - xem ngày còn hạn\n"
                "• /hethan 5 - khách sắp hết hạn\n"
                "• /ctv - danh sách CTV đã đăng ký\n"
                "• /ctv CTV-123456 - xem chi tiết hoa hồng CTV"
            )
            return jsonify({'ok': True})

        if low.startswith('/cho') or low == 'cho':
            _mkt_v160_tg_send(chat_id, _mkt_v160_pending_premium_list())
            return jsonify({'ok': True})
        if low.startswith('/hethan') or low.startswith('hethan'):
            parts = text.split()
            days = int(parts[1]) if len(parts) > 1 and parts[1].isdigit() else 5
            _mkt_v160_tg_send(chat_id, _mkt_v160_expiring_list(days))
            return jsonify({'ok': True})
        if low.startswith('/ngay') or low.startswith('/han') or low.startswith('ngay') or low.startswith('han'):
            device = _mkt_v160_find_device(text)
            _mkt_v160_tg_send(chat_id, _mkt_v160_subscription_summary(device))
            return jsonify({'ok': True})
        if low.startswith('/ctv') or low.startswith('ctv'):
            key = text.split(maxsplit=1)[1] if len(text.split(maxsplit=1)) > 1 else ''
            if key:
                _mkt_v160_tg_send(chat_id, _mkt_v160_ctv_summary(key))
            else:
                _mkt_v160_tg_send(chat_id, _mkt_v164_ctv_registered_list(20))
            return jsonify({'ok': True})
        if low.startswith('/duyet') or low.startswith('duyet'):
            parts = text.split()
            req_id = int(parts[1]) if len(parts) > 1 and parts[1].isdigit() else 0
            _device_for_reply = ''
            if req_id:
                try:
                    _conn = db(); _c = _conn.cursor()
                    _c.execute('SELECT device_id FROM premium_upgrade_requests WHERE id=?', (req_id,))
                    _r = _c.fetchone(); _conn.close()
                    _device_for_reply = (_r[0] if _r else '') or ''
                except Exception:
                    _device_for_reply = ''
            ok = approve_premium_request(req_id, status='Đã duyệt', admin_note='Duyệt từ Telegram') if req_id else False
            if ok and _device_for_reply:
                try:
                    save_support_message(_device_for_reply, 'admin', 'Gói Premium của anh/chị đã được kích hoạt thành công. Anh/chị tải lại trang hoặc chờ vài giây để hệ thống tự mở khóa nhé.')
                except Exception as _e:
                    print('Telegram /duyet customer notify skipped:', _e)
            _mkt_v160_tg_send(chat_id, '✅ Đã duyệt Premium #' + str(req_id) if ok else '❌ Không duyệt được. Dùng: /duyet 123')
            return jsonify({'ok': True})
        if low.startswith('/tuchoi') or low.startswith('/reject') or low.startswith('tuchoi') or low.startswith('reject'):
            parts = text.split()
            req_id = int(parts[1]) if len(parts) > 1 and parts[1].isdigit() else 0
            ok = approve_premium_request(req_id, status='Từ chối', admin_note='Từ chối từ Telegram') if req_id else False
            _mkt_v160_tg_send(chat_id, '⚠️ Đã từ chối #' + str(req_id) if ok else '❌ Không xử lý được. Dùng: /tuchoi 123')
            return jsonify({'ok': True})
        if low.startswith('/reply') or low.startswith('reply'):
            # /reply MKT-ABC nội dung
            rest = text.split(maxsplit=2)
            if len(rest) >= 3:
                device = rest[1].strip().upper()
                body = rest[2].strip()
                save_support_message(device, 'admin', body)
                _mkt_v160_tg_send(chat_id, f"✅ Đã gửi phản hồi cho khách <b>{tg_safe(device)}</b>\n\n{tg_safe(body)}")
            else:
                _mkt_v160_tg_send(chat_id, 'Cú pháp: /reply MKT-ABC nội dung cần gửi\nHoặc: reply MKT-ABC nội dung cần gửi')
            return jsonify({'ok': True})

        # Messenger-style: admin Reply trực tiếp vào ticket Telegram của khách.
        # Hệ thống tìm device_id bằng message_id đã map; nếu không có thì fallback đọc ID trong nội dung tin được reply.
        reply_msg = (message.get('reply_to_message') or {})
        reply_mid = reply_msg.get('message_id')
        device = _mkt_v162_find_ticket_device(chat_id, reply_mid, reply_text)
        if device and str(chat_id) == str(os.getenv('TELEGRAM_CHAT_ID','').strip()):
            save_support_message(device, 'admin', text)
            _mkt_v162_mark_ticket_replied(chat_id, reply_mid)
            _mkt_v160_tg_send(chat_id, f"✅ Đã gửi phản hồi cho khách <b>{tg_safe(device)}</b>\n\n{tg_safe(text)}")
            return jsonify({'ok': True})

        return jsonify({'ok': True, 'ignored': True})
    except Exception as e:
        print('Telegram webhook error:', e)
        return jsonify({'ok': False, 'error': str(e)}), 200


@app.route('/admin/telegram_admin_help')
def admin_telegram_admin_help_route():
    return jsonify({
        'success': True,
        'message': 'Telegram Admin Center đã sẵn sàng.',
        'set_webhook': (request.url_root or '').rstrip('/').replace('http://','https://',1) + '/telegram/set_webhook?secret=' + os.getenv('TELEGRAM_WEBHOOK_SECRET',''),
        'commands': ['/cho','/duyet 123','/tuchoi 123','/reply MKT-ABC nội dung','/ngay MKT-ABC','/hethan 5','/ctv CTV-123456']
    })


# ============================================================
# CTV MOBILE DIRECT OPEN + REGISTER BUTTON FIX
# Giữ nguyên cấu trúc menu/cài đặt hiện tại.
# Chỉ vá lỗi: link CTV / nút CTV trên điện thoại / nút Tạo link CTV.
# ============================================================
@app.after_request
def _mkt_ctv_mobile_register_fix(response):
    try:
        ctype = response.headers.get('Content-Type', '')
        if 'text/html' not in ctype.lower():
            return response
        html = response.get_data(as_text=True)
        if not html or 'affiliateCenterSection' not in html or 'ctv-mobile-direct-fix-js' in html:
            return response
        inject = """
<style id="ctv-mobile-direct-fix-style">
  #mobileCtvQuickBtn{z-index:2147483646!important;pointer-events:auto!important;touch-action:manipulation!important}
  [data-aff-menu="1"],a[href="#affiliate_center"]{pointer-events:auto!important;touch-action:manipulation!important}
  #affiliateCenterSection.ctv-mobile-open{display:block!important;visibility:visible!important;opacity:1!important}
  @media(max-width:760px){
    #mobileCtvQuickBtn{left:12px!important;bottom:84px!important;display:flex!important}
    #affiliateCenterSection .aff-btn{min-height:44px!important}
  }
</style>
<script id="ctv-mobile-direct-fix-js">
(function(){
  'use strict';
  function qs(s){return document.querySelector(s)}
  function qsa(s){return Array.prototype.slice.call(document.querySelectorAll(s))}
  function toast(msg){
    var t=document.getElementById('affToast');
    if(!t){t=document.createElement('div');t.id='affToast';t.className='aff-toast';document.body.appendChild(t)}
    t.textContent=msg;t.style.display='block';setTimeout(function(){t.style.display='none'},2600);
  }
  function hideOtherSections(){
    qsa('main > section, main > div.module, main > div.card, main > div.app-module-section,.module-section,.content-section').forEach(function(el){
      if(el && el.id!=='affiliateCenterSection' && el.id!=='affiliateAdminSection') el.style.display='none';
    });
  }
  function loadAffiliate(){
    if(typeof window.affiliateLoadMe==='function'){
      try{window.affiliateLoadMe()}catch(e){}
    }
  }
  function openCTV(e){
    if(e){e.preventDefault();e.stopPropagation();if(e.stopImmediatePropagation)e.stopImmediatePropagation();}
    var sec=qs('#affiliateCenterSection');
    if(!sec){toast('Chưa tìm thấy khung CTV trong trang.');return false;}
    hideOtherSections();
    sec.style.display='block';
    sec.classList.add('ctv-active','ctv-mobile-open');
    loadAffiliate();
    try{history.replaceState(null,'','#affiliate_center')}catch(_e){}
    setTimeout(function(){try{sec.scrollIntoView({behavior:'smooth',block:'start'})}catch(_e){window.scrollTo(0,0)}},80);
    return false;
  }
  window.openAffiliateCenter=openCTV;
  var oldOpen=window.openModule;
  window.openModule=function(name){
    if(name==='affiliate_center') return openCTV();
    if(name==='affiliate_admin') return false;
    if(typeof oldOpen==='function') return oldOpen.apply(this,arguments);
    return true;
  };
  function bindOpeners(){
    qsa('#mobileCtvQuickBtn,[data-aff-menu="1"],a[href="#affiliate_center"],[onclick*="affiliate_center"]').forEach(function(el){
      if(!el || el.__ctvBound) return;
      el.__ctvBound=true;
      el.style.pointerEvents='auto';
      el.addEventListener('click',openCTV,true);
      el.addEventListener('touchstart',function(ev){openCTV(ev)}, {capture:true,passive:false});
    });
    var btn=qs('#mobileCtvQuickBtn');
    if(btn){btn.type='button';btn.style.display='flex';}
  }
  window.affiliateSaveProfile=function(){
    var name=(qs('#affName')&&qs('#affName').value||'').trim();
    var phone=(qs('#affPhone')&&qs('#affPhone').value||'').trim();
    var email=(qs('#affEmail')&&qs('#affEmail').value||'').trim();
    fetch('/api/affiliate/me',{
      method:'POST',
      credentials:'same-origin',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({full_name:name,phone:phone,email:email})
    }).then(function(r){return r.json()}).then(function(d){
      if(!d || !d.ok){toast((d&&d.message)||'Không tạo được link CTV.');return;}
      if(qs('#affName')) qs('#affName').value=d.full_name||name;
      if(qs('#affPhone')) qs('#affPhone').value=d.phone||phone;
      if(qs('#affEmail')) qs('#affEmail').value=d.email||email;
      if(qs('#affCode')) qs('#affCode').textContent=d.affiliate_code||'---';
      if(qs('#affLevel')) qs('#affLevel').textContent=d.level_name||'CTV thường';
      if(qs('#affPercent')) qs('#affPercent').textContent=d.commission_percent||20;
      if(qs('#affRefLink')) qs('#affRefLink').value=d.pretty_link||d.ref_link||'';
      toast('Đã tạo link CTV. Bấm Sao chép để gửi khách.');
      loadAffiliate();
    }).catch(function(){
      toast('Mạng chậm hoặc trình duyệt chặn. Vui lòng bấm lại Tạo link CTV.');
    });
    return false;
  };
  function bindRegister(){
    qsa('button').forEach(function(b){
      var tx=(b.innerText||b.textContent||'').trim();
      if(/Tạo link CTV miễn phí|Đăng ký CTV|Đăng kí CTV/i.test(tx)){
        b.type='button';
        b.onclick=function(e){e.preventDefault();e.stopPropagation();return window.affiliateSaveProfile();};
        if(!b.__ctvRegTouch){
          b.__ctvRegTouch=true;
          b.addEventListener('touchstart',function(e){e.preventDefault(); return window.affiliateSaveProfile();},{passive:false});
        }
      }
    });
  }
  function init(){
    bindOpeners();bindRegister();
    var url=new URL(location.href);
    var ref=(url.searchParams.get('ref')||'').trim();
    if(ref){try{document.cookie='affiliate_code='+encodeURIComponent(ref.toUpperCase())+';path=/;max-age='+(60*60*24*90)+';SameSite=Lax'}catch(e){}}
    if(location.hash==='#affiliate_center' || /^\/ctv\//i.test(location.pathname)){setTimeout(openCTV,250);}
  }
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);else init();
  setTimeout(init,700);setTimeout(init,1800);setTimeout(init,3500);
})();
</script>
"""
        if '</body>' in html:
            html = html.replace('</body>', inject + '</body>', 1)
        else:
            html += inject
        response.set_data(html)
        response.headers['Content-Length'] = str(len(response.get_data()))
    except Exception as e:
        try:
            print('CTV mobile register fix skipped:', e)
        except Exception:
            pass
    return response



