@app.after_request
def mkt_v196_fb_full_publish_center_after_request(response):
    try:
        ctype = (response.headers.get('Content-Type') or '').lower()
        if 'text/html' in ctype:
            body = response.get_data(as_text=True)
            if 'mkt-v196-fb-full-publish-center-js' not in body and '</body>' in body:
                body = body.replace('</body>', MKT_V196_FB_FULL_PUBLISH_CENTER + '</body>')
                response.set_data(body)
                response.headers['Content-Length'] = str(len(body.encode('utf-8')))
    except Exception as _e:
        print('mkt_v196_fb_full_publish_center_after_request skipped:', _e)
    return response
